import { useState, useEffect } from "react";
import "./Tasks.css";

export default function Tasks() {
  const [task, setTask] = useState("");
  const [tasks, setTasks] = useState([]);
  const [editId, setEditId] = useState(null);
  const [filter, setFilter] = useState("all");

  useEffect(() => {
    const savedTasks = JSON.parse(localStorage.getItem("tasks"));
    if (savedTasks) setTasks(savedTasks);
  }, []);

  useEffect(() => {
    localStorage.setItem("tasks", JSON.stringify(tasks));
  }, [tasks]);

  const handleSubmit = () => {
    if (task.trim() === "") return;

    if (editId) {
      setTasks(
        tasks.map((t) =>
          t.id === editId ? { ...t, text: task } : t
        )
      );
      setEditId(null);
    } else {
      setTasks([
        ...tasks,
        { id: Date.now(), text: task, completed: false },
      ]);
    }

    setTask("");
  };

  const handleEdit = (t) => {
    setTask(t.text);
    setEditId(t.id);
  };

  const handleDelete = (id) => {
    setTasks(tasks.filter((t) => t.id !== id));
  };

  const handleToggle = (id) => {
    setTasks(
      tasks.map((t) =>
        t.id === id ? { ...t, completed: !t.completed } : t
      )
    );
  };

  // 🔥 FILTER LOGIC
  const filteredTasks = tasks.filter((t) => {
    if (filter === "completed") return t.completed;
    if (filter === "pending") return !t.completed;
    return true;
  });

  return (
    <div className="tasks-container">
      <h2>Task Manager</h2>

      <input
        type="text"
        placeholder="Enter task..."
        value={task}
        onChange={(e) => setTask(e.target.value)}
        className="task-input"
      />

      <button onClick={handleSubmit} className="task-btn">
        {editId ? "Update" : "Add"}
      </button>

      <div className="filter-buttons">
        <button onClick={() => setFilter("all")}>All</button>
        <button onClick={() => setFilter("completed")}>Completed</button>
        <button onClick={() => setFilter("pending")}>Pending</button>
      </div>

      <ul className="task-list">
        {filteredTasks.map((t) => (
          <li key={t.id} className="task-item">
            <span className={t.completed ? "completed" : ""}>
              {t.text}
            </span>

            <button className="task-action-btn" onClick={() => handleToggle(t.id)}>✔</button>
            <button className="task-action-btn" onClick={() => handleEdit(t)}>✏️</button>
            <button className="task-action-btn" onClick={() => handleDelete(t.id)}>❌</button>
          </li>
        ))}
      </ul>
    </div>
  );
}
